node -e "
const fs = require('fs');
const file = '{FILE}';
const content = fs.readFileSync(file, 'utf8');
const issues = [];

// Check for console.log (dev code)
if (/console\.log/g.test(content)) issues.push('⚠ console.log found (remove in production)');

// Check for floating promises (common bug)
if (/await.*\.then\(|Promise.*\.then.*\(/.test(content)) issues.push('⚠ Mixed async/await with .then() (simplify)');

// Check for mutation outside state
if (/const state = .*?;/s.test(content) && /state\.[a-zA-Z]+ =/g.test(content)) {
  if (!content.includes('render()')) issues.push('⚠ State mutation detected without render() call');
}

if (issues.length > 0) {
  console.warn(issues.join('\\n'));
  process.exit(1);
} else {
  console.log('✓ JS code quality check passed');
}
" -- '{FILE}' || true

node -e "
const fs = require('fs');
const file = '{FILE}';
const content = fs.readFileSync(file, 'utf8');
const issues = [];

// Check for hard-coded colors (should use CSS custom properties)
if (/#[0-9a-fA-F]{3,6}(?!.*:root)/g.test(content)) issues.push('⚠ Hard-coded colors detected (use CSS variables)');

// Check for responsive breakpoints
if (!/@media/.test(content)) issues.push('ℹ Note: No media queries found (mobile-first design expected)');

if (issues.length > 0) {
  console.warn(issues.join('\\n'));
} else {
  console.log('✓ CSS style check passed');
}
" -- '{FILE}' || true
